mapper.select:
SELECT fieldValue,
    tagName,
    tagValue,
    timestampInEpoch
FROM systemMetricDouble
WHERE applicationName = #{applicationName}
    AND metricName = #{metricName}
    AND fieldName = #{fieldName}

        AND tagName = #{tag.name} AND tagValue = #{tag.value}

    AND timestampInEpoch BETWEEN #{range.from} AND #{range.to}
LIMIT ${limit}
